request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?predecessorName ?predecessorType ?edgeName ?gatewayDir WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge bbo:has_targetRef <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-D796B62F-F6F4-4005-9B9A-4EACC480AF78> .
  ?edge bbo:has_sourceRef ?predecessor .
  OPTIONAL { ?predecessor bbo:name ?predecessorName . }
  ?predecessor a ?predecessorType .
  OPTIONAL { ?edge bbo:name ?edgeName . }
  OPTIONAL { ?predecessor bboExt:gatewayDirection ?gatewayDir . }
}
LIMIT 25
